<div class="page-heading"><div><h2>Movimientos de inventario</h2><p>Historial de entradas y salidas con saldos anteriores y posteriores.</p></div><a class="btn btn-success" href="index.php?route=reportes/movimientos-excel"><i class="bi bi-file-earmark-excel"></i> Exportar Excel</a></div><div class="card border-0 shadow-sm"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Fecha</th><th>Número</th><th>Tipo</th><th>Producto</th><th class="text-end">Cantidad</th><th class="text-end">Anterior</th><th class="text-end">Posterior</th><th>Usuario</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars((string)$r['FechaMovimiento'])?></td><td><strong><?=htmlspecialchars($r['NumeroMovimiento'])?></strong></td><td><span class="badge text-bg-<?=$r['Naturaleza']==='E'?'success':'danger'?>"><?=htmlspecialchars($r['Tipo'])?></span></td><td><?=htmlspecialchars($r['Codigo'].' - '.$r['Producto'])?></td><td class="text-end"><?=number_format((float)$r['Cantidad'],2)?></td><td class="text-end"><?=number_format((float)$r['StockAnterior'],2)?></td><td class="text-end fw-bold"><?=number_format((float)$r['StockPosterior'],2)?></td><td><?=htmlspecialchars($r['NombreUsuario'])?></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="8" class="text-center py-5 text-muted">No se han registrado movimientos.</td></tr><?php endif;?></tbody></table></div></div>
